document.addEventListener('DOMContentLoaded', function() {


	// ========== 1. БУРГЕР-МЕНЮ ==========
	const burger = document.querySelector('.burger');
	const navLinks = document.querySelectorAll('.nav__link');

	const body = document.body;

	if (burger) {
		burger.addEventListener('click', function() {
			this.classList.toggle('burger--active');
			document.body.classList.toggle('no-scroll');
		});
	}



	function debounce(func, delay) {
		let timeout;
		return function() {
			clearTimeout(timeout);
			timeout = setTimeout(func, delay);
		};
	}

	function checkWidth() {
		if (window.innerWidth < 768) {
			if (navLinks.length > 0) {
				navLinks.forEach(link => {
					link.addEventListener('click', function(e) {
						burger.classList.remove('burger--active');
						document.body.classList.remove('no-scroll');
					});
				});
			}
		}
	}

	window.addEventListener('resize', debounce(checkWidth, 150));
	checkWidth();

	function checkBurgerWidth() {
		if (window.innerWidth > 768) {
			body.classList.remove('no-scroll');
			if (burger) {
				burger.classList.remove('burger--active');
			}
		}
	}

	checkBurgerWidth();
	window.addEventListener('resize', checkBurgerWidth);

	// ========== 2. АНИМАЦИЯ ТОЧЕК ==========
	let dotsInterval = null;
	let currentIndex = 0;
	const activeSequence = [1, 2, 3, 4, 5, 10, 11, 12, 13, 14, 19, 20, 21, 22, 23, 28, 29, 30, 31, 32];
	const activeClass = 'operating-procedure__dot--active';

	function removeAllActive(dots) {
		dots.forEach(dot => dot.classList.remove(activeClass));
	}

	function activateNext(dots) {
		if (!dots || dots.length === 0) return;

		removeAllActive(dots);

		const activeIndex = activeSequence[currentIndex];
		if (activeIndex >= 0 && activeIndex < dots.length) {
			dots[activeIndex].classList.add(activeClass);
		}

		currentIndex = (currentIndex + 1) % activeSequence.length;
	}

	function startDotsAnimation() {
		const dots = document.querySelectorAll('.operating-procedure__dot');
		if (dots.length === 0) return;

		if (dotsInterval) clearInterval(dotsInterval);
		currentIndex = 0;

		dotsInterval = setInterval(() => activateNext(dots), 2000);

		// Пауза при наведении
		dots.forEach(dot => {
			dot.removeEventListener('mouseenter', () => clearInterval(dotsInterval));
			dot.removeEventListener('mouseleave', () => {
				if (dotsInterval) clearInterval(dotsInterval);
				dotsInterval = setInterval(() => activateNext(dots), 2000);
			});

			dot.addEventListener('mouseenter', () => clearInterval(dotsInterval));
			dot.addEventListener('mouseleave', () => {
				dotsInterval = setInterval(() => activateNext(dots), 2000);
			});
		});
	}

	function stopDotsAnimation() {
		if (dotsInterval) {
			clearInterval(dotsInterval);
			dotsInterval = null;
		}
	}

	function checkDotsWidth() {
		if (window.innerWidth > 1090) {
			startDotsAnimation();
		} else {
			stopDotsAnimation();
			const dots = document.querySelectorAll('.operating-procedure__dot');
			removeAllActive(dots);
		}
	}

	checkDotsWidth();
	window.addEventListener('resize', checkDotsWidth);

	// ========== 3. RANGE ПОЛЗУНОК ==========
	const range = document.querySelector('.form__range');
	const rangeOutput = document.querySelector('.form__range-output');

	if (range && rangeOutput) {
		function updateRange() {
			const value = range.value;
			rangeOutput.textContent = value + '%';
		}

		range.addEventListener('input', updateRange);
		updateRange();
	}

	// ========== 4. ЗАГРУЗКА ФАЙЛА ==========
	const fileInput = document.getElementById('file');
	const fileButton = document.querySelector('.form__file-button');
	const fileWrapper = document.querySelector('.form__file-wrapper');

	// Создаём элементы, если их нет
	let fileNameDisplay = fileWrapper?.querySelector('.form__file-name');
	if (!fileNameDisplay && fileWrapper) {
		fileNameDisplay = document.createElement('span');
		// fileNameDisplay.className = 'form__file-name';
		// fileNameDisplay.textContent = 'Файл не выбран';
		// fileWrapper.appendChild(fileNameDisplay);
	}

	let fileError = fileWrapper?.querySelector('.form__file-error');
	if (!fileError && fileWrapper) {
		fileError = document.createElement('span');
		fileError.className = 'form__file-error';
		fileWrapper.appendChild(fileError);
	}

	function showFileError(message) {
		if (fileError) {
			fileError.textContent = message;
			fileError.style.display = 'block';
		}
		if (fileButton) {
			fileButton.style.borderColor = '#dc3545';
			fileButton.style.backgroundColor = 'rgba(220, 53, 69, 0.05)';
		}
		setTimeout(() => hideFileError(), 5000);
	}

	function hideFileError() {
		if (fileError) fileError.style.display = 'none';
		if (fileButton) {
			fileButton.style.borderColor = '';
			fileButton.style.backgroundColor = '';
		}
	}

	function formatFileSize(bytes) {
		if (bytes === 0) return null;
		const sizes = ['Б', 'КБ', 'МБ', 'ГБ'];
		const i = Math.floor(Math.log(bytes) / Math.log(1024));
		return (bytes / Math.pow(1024, i)).toFixed(1) + ' ' + sizes[i];
	}

	if (fileInput && fileButton && fileNameDisplay) {
		fileButton.addEventListener('click', function(e) {
			e.preventDefault();
			fileInput.click();
		});

		fileInput.addEventListener('change', function() {
			const file = this.files[0];
			const maxSize = parseInt(this.dataset.maxSize) || 5242880;

			if (file && file.size > maxSize) {
				const sizeMB = (maxSize / 1024 / 1024).toFixed(1);
				showFileError(`Размер файла не должен превышать ${sizeMB}MB`);
				fileNameDisplay.textContent = 'Файл не выбран';
				fileNameDisplay.classList.remove('has-file');
				this.value = '';
				return;
			}

			const allowedExtensions = ['jpg', 'jpeg', 'png', 'pdf', 'doc', 'docx', 'txt'];
			if (file) {
				const fileExtension = file.name.split('.').pop().toLowerCase();
				if (!allowedExtensions.includes(fileExtension)) {
					showFileError(`Разрешённые форматы: ${allowedExtensions.join(', ')}`);
					fileNameDisplay.textContent = 'Файл не выбран';
					fileNameDisplay.classList.remove('has-file');
					this.value = '';
					return;
				}
			}

			if (file) {
				fileNameDisplay.textContent = file.name;
				fileNameDisplay.classList.add('has-file');
				hideFileError();
				const fileSize = formatFileSize(file.size);
				if (fileSize) fileNameDisplay.title = `Размер: ${fileSize}`;
			} else {
				fileNameDisplay.textContent = 'Файл не выбран';
				fileNameDisplay.classList.remove('has-file');
				fileNameDisplay.removeAttribute('title');
				hideFileError();
			}
		});
	}

	// ========== 5. КАСТОМНЫЙ СЕЛЕКТ ==========
	class CustomSelect {
		constructor(selectElement) {
			this.select = selectElement;
			this.trigger = selectElement.querySelector('.custom-select__trigger');
			this.dropdown = selectElement.querySelector('.custom-select__dropdown'); // ✅ раскомментировано
			this.options = selectElement.querySelectorAll('.custom-select__option');
			this.valueSpan = selectElement.querySelector('.custom-select__value');
			this.hiddenInput = document.querySelector('#select');
			this.isOpen = false;

			this.init();
		}

		init() {
			if (!this.trigger) return;

			this.trigger.addEventListener('click', (e) => {
				e.stopPropagation();
				this.toggle();
			});

			this.options.forEach(option => {
				option.addEventListener('click', (e) => {
					e.stopPropagation();
					this.selectOption(option);
				});
			});

			document.addEventListener('click', () => this.close());
			this.select.addEventListener('click', (e) => e.stopPropagation());
		}

		toggle() {
			this.isOpen ? this.close() : this.open();
		}

		open() {
			document.querySelectorAll('.custom-select').forEach(select => {
				if (select !== this.select) select.classList.remove('open');
			});

			this.isOpen = true;
			this.select.classList.add('open');
		}

		close() {
			this.isOpen = false;
			this.select.classList.remove('open');
		}

		selectOption(option) {
			const text = option.textContent;
			const value = option.dataset.value;

			this.valueSpan.textContent = text;
			this.options.forEach(opt => opt.classList.remove('selected'));
			option.classList.add('selected');
			this.select.dataset.value = value;

			if (this.hiddenInput) {
				this.hiddenInput.value = text;
				this.hiddenInput.blur();
				const inputChangeEvent = new Event('change', { bubbles: true });
				this.hiddenInput.dispatchEvent(inputChangeEvent);
			}

			this.close();

			const changeEvent = new CustomEvent('change', {
				detail: { value: value, text: text },
				bubbles: true
			});
			this.select.dispatchEvent(changeEvent);

			console.log('Выбрано:', text, 'Значение:', value);
		}

		setValue(value) {
			const option = Array.from(this.options).find(opt => opt.dataset.value === value);
			if (option) this.selectOption(option);
		}

		getValue() {
			return {
				value: this.select.dataset.value,
				text: this.valueSpan.textContent
			};
		}
	}

	const customSelects = document.querySelectorAll('.custom-select');
	customSelects.forEach(select => {
		new CustomSelect(select);
	});
});